#include <bits/stdc++.h>
using namespace std;
long long mod=1e9+7;
unsigned long long dp[200005];
int main(){
    int n,a,b,c;
    cin>>n>>a>>b>>c;
    if(n==c){
        cout<<1;
        return 0;
    }
    for(int i=c+1;i<=n;i++){
        unsigned long long x=1,y=1;
        if(i-a>c)x=dp[i-a];
        if(i-b>c)y=dp[i-b];
        dp[i]=(x+y)%mod;
    }
    cout<<dp[n];
    return 0;
}
